-- RH Supabase schema for packages, 40 template UI, Aira v2, leads and live customizer
-- Generated for Restu Harmoni source: services-main-rh-live-customizer-v1-sw-ready

create extension if not exists pgcrypto;

create table if not exists public.rh_packages (
  id uuid primary key default gen_random_uuid(),
  package_code text unique not null,
  package_name text not null,
  template_access integer not null default 10,
  focus text,
  objective text,
  features jsonb not null default '[]'::jsonb,
  sort_order integer not null default 0,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.rh_templates (
  id uuid primary key default gen_random_uuid(),
  template_id text unique not null,
  template_name text not null,
  package_code text not null,
  package_name text not null,
  industry text,
  headline text,
  subheadline text,
  ui_concept text,
  suitable_for text,
  theme_color text,
  image_url text,
  file_path text,
  metadata jsonb not null default '{}'::jsonb,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.rh_services (
  id uuid primary key default gen_random_uuid(),
  service_code text unique not null,
  service_name text not null,
  recommended_package text,
  metadata jsonb not null default '{}'::jsonb,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.rh_service_template_map (
  id uuid primary key default gen_random_uuid(),
  service_code text not null references public.rh_services(service_code) on delete cascade,
  template_id text not null references public.rh_templates(template_id) on delete cascade,
  recommended_package text,
  score integer not null default 100,
  reason text,
  created_at timestamptz not null default now(),
  unique(service_code, template_id)
);

create table if not exists public.rh_leads (
  id uuid primary key default gen_random_uuid(),
  company_name text,
  contact_name text,
  phone text,
  whatsapp text,
  email text,
  location text,
  service_type text,
  business_goal text,
  package_recommended text,
  template_selected text,
  source text not null default 'website',
  status text not null default 'new',
  notes text,
  payload jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.rh_template_configs (
  id uuid primary key default gen_random_uuid(),
  lead_id uuid references public.rh_leads(id) on delete set null,
  session_id text,
  company_name text,
  service_type text,
  location text,
  whatsapp text,
  template_id text references public.rh_templates(template_id) on delete set null,
  package_name text,
  theme_color text,
  logo_url text,
  config jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.rh_aira_sessions (
  id uuid primary key default gen_random_uuid(),
  lead_id uuid references public.rh_leads(id) on delete set null,
  session_key text,
  service_type text,
  messages jsonb not null default '[]'::jsonb,
  recommendation jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create or replace function public.rh_set_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists trg_rh_packages_updated_at on public.rh_packages;
create trigger trg_rh_packages_updated_at before update on public.rh_packages for each row execute function public.rh_set_updated_at();

drop trigger if exists trg_rh_templates_updated_at on public.rh_templates;
create trigger trg_rh_templates_updated_at before update on public.rh_templates for each row execute function public.rh_set_updated_at();

drop trigger if exists trg_rh_services_updated_at on public.rh_services;
create trigger trg_rh_services_updated_at before update on public.rh_services for each row execute function public.rh_set_updated_at();

drop trigger if exists trg_rh_leads_updated_at on public.rh_leads;
create trigger trg_rh_leads_updated_at before update on public.rh_leads for each row execute function public.rh_set_updated_at();

drop trigger if exists trg_rh_template_configs_updated_at on public.rh_template_configs;
create trigger trg_rh_template_configs_updated_at before update on public.rh_template_configs for each row execute function public.rh_set_updated_at();

drop trigger if exists trg_rh_aira_sessions_updated_at on public.rh_aira_sessions;
create trigger trg_rh_aira_sessions_updated_at before update on public.rh_aira_sessions for each row execute function public.rh_set_updated_at();

create index if not exists idx_rh_templates_package on public.rh_templates(package_code);
create index if not exists idx_rh_templates_active on public.rh_templates(active);
create index if not exists idx_rh_services_package on public.rh_services(recommended_package);
create index if not exists idx_rh_service_template_service on public.rh_service_template_map(service_code);
create index if not exists idx_rh_service_template_template on public.rh_service_template_map(template_id);
create index if not exists idx_rh_leads_status_created on public.rh_leads(status, created_at desc);
create index if not exists idx_rh_template_configs_lead on public.rh_template_configs(lead_id);
create index if not exists idx_rh_aira_sessions_lead on public.rh_aira_sessions(lead_id);

