-- Public read access for package/template catalog. Keep lead/config/session writes controlled by API keys or Edge Functions in production.
alter table public.rh_packages enable row level security;
alter table public.rh_templates enable row level security;
alter table public.rh_services enable row level security;
alter table public.rh_service_template_map enable row level security;
alter table public.rh_leads enable row level security;
alter table public.rh_template_configs enable row level security;
alter table public.rh_aira_sessions enable row level security;

drop policy if exists "Public read RH packages" on public.rh_packages;
create policy "Public read RH packages" on public.rh_packages for select using (active = true);
drop policy if exists "Public read RH templates" on public.rh_templates;
create policy "Public read RH templates" on public.rh_templates for select using (active = true);
drop policy if exists "Public read RH services" on public.rh_services;
create policy "Public read RH services" on public.rh_services for select using (active = true);
drop policy if exists "Public read RH service template map" on public.rh_service_template_map;
create policy "Public read RH service template map" on public.rh_service_template_map for select using (true);

-- Optional frontend insert policies. Disable/remove if all writes go through secure backend/Edge Functions.
drop policy if exists "Public insert RH leads" on public.rh_leads;
create policy "Public insert RH leads" on public.rh_leads for insert with check (true);
drop policy if exists "Public insert RH template configs" on public.rh_template_configs;
create policy "Public insert RH template configs" on public.rh_template_configs for insert with check (true);
drop policy if exists "Public insert RH Aira sessions" on public.rh_aira_sessions;
create policy "Public insert RH Aira sessions" on public.rh_aira_sessions for insert with check (true);
